def categorize_dinosaur_weight(weight_kg):
    if weight_kg < 10:
        return 'Very small (<10 kg)'
    elif 10 <= weight_kg < 100:
        return 'Small (10-100 kg)'
    elif 100 <= weight_kg < 1000:
        return 'Medium (100-1000 kg)'
    elif 1000 <= weight_kg < 10000:
        return 'Large (1-10 tonnes)'
    else:
        return 'Very large (>10 tonnes)'

# Example usage:
print(categorize_dinosaur_weight(500))  # Output: Medium (100-1000 kg)
print(categorize_dinosaur_weight(5000))  # Output: Large (1-10 tonnes)
